const body = $input.first().json.body || {};
const { license_plate, booking_ref, name, postal_code, conversation_id } = body;
const hasLP = !!license_plate;
const hasBR = !!booking_ref;
const hasNP = name && postal_code;
if (!hasLP && !hasBR && !hasNP) {
  return [{ json: { __error: true, message: 'missing_identifier' } }];
}
return [{ json: {
  license_plate: license_plate ? license_plate.toUpperCase().replace(/\s+/g, '') : null,
  booking_ref:  booking_ref || null,
  name:         name || null,
  postal_code:  postal_code || null,
  conversation_id: conversation_id || null,
} }];

const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 10000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const i = $input.first().json;
const sb = $vars.CARGLASS_SUPABASE_URL;
const headers = { apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY };
async function fetchJson(url) {
  const r = await fetch(url, { headers });
  if (!r.ok) return [];
  return await r.json();
}
let customerId = null;
if (i.license_plate) {
  const v = await fetchJson(`${sb}/rest/v1/vehicles?license_plate=ilike.*${encodeURIComponent(i.license_plate)}*&select=customer_id&limit=1`);
  if (v.length) customerId = v[0].customer_id;
}
if (!customerId && i.booking_ref) {
  const a = await fetchJson(`${sb}/rest/v1/appointments?booking_reference=eq.${encodeURIComponent(i.booking_ref)}&select=customer_id&limit=1`);
  if (a.length) customerId = a[0].customer_id;
}
if (!customerId && i.name && i.postal_code) {
  const parts = i.name.trim().split(/\s+/);
  const last = parts[parts.length - 1];
  const c = await fetchJson(`${sb}/rest/v1/customers?last_name=ilike.*${encodeURIComponent(last)}*&postal_code=eq.${encodeURIComponent(i.postal_code)}&select=id&limit=1`);
  if (c.length) customerId = c[0].id;
}
if (!customerId) {
  return [{ json: { ok: true, data: { found: false, customer: null, recent_appointments: [] } } }];
}
const cust = await fetchJson(`${sb}/rest/v1/customers?id=eq.${customerId}&select=id,first_name,last_name,phone_e164,language`);
const appts = await fetchJson(`${sb}/rest/v1/appointments?customer_id=eq.${customerId}&order=scheduled_start.desc&limit=3&select=booking_reference,status,scheduled_start,branches(name)`);
return [{ json: { ok: true, data: {
  found: true,
  customer: cust[0] || null,
  recent_appointments: (appts || []).map(a => ({
    booking_reference: a.booking_reference,
    status: a.status,
    scheduled_start: a.scheduled_start,
    branch_name: a.branches ? a.branches.name : null,
  })),
} } }];
